import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, useLocation } from 'react-router-dom';
import axios from 'axios';
import './App.css';
import BookList from './pages/BookList';
import MyBorrows from './pages/MyBorrows';
import Notifications from './pages/Notifications';
import AdminBooks from './pages/AdminBooks';

function App() {
  const [userIdInput, setUserIdInput] = useState('1');
  const [currentUserId, setCurrentUserId] = useState(1);
  const [currentUser, setCurrentUser] = useState(null);
  const location = useLocation();

  useEffect(() => {
    fetchUserDetails(currentUserId);
  }, [currentUserId]);

  const fetchUserDetails = async (id) => {
    try {
      const response = await axios.get(`http://localhost:8080/api/users/${id}`);
      setCurrentUser(response.data);
    } catch (error) {
      console.warn("User fetch failed - user may not exist in database yet:", error);
      setCurrentUser(null);
    }
  };

  const handleUserChange = (e) => {
    const val = e.target.value;
    setUserIdInput(val);
    const parsed = parseInt(val, 10);
    if (!isNaN(parsed) && parsed > 0) {
      setCurrentUserId(parsed);
    }
  };

  return (
    <div className="app-container">
      <nav className="navbar">
        <h1>Library Portal</h1>
        <div className="nav-links">
          <Link to="/" className={`nav-link ${location.pathname === '/' ? 'active' : ''}`}>
            Books
          </Link>
          <Link to="/borrows" className={`nav-link ${location.pathname === '/borrows' ? 'active' : ''}`}>
            My Borrows
          </Link>
          <Link to="/notifications" className={`nav-link ${location.pathname === '/notifications' ? 'active' : ''}`}>
            Notifications
          </Link>
          <Link to="/admin" className={`nav-link ${location.pathname === '/admin' ? 'active' : ''}`}>
            Admin Panel
          </Link>
        </div>
        <div className="user-selector">
          <label htmlFor="userId">User ID:</label>
          <input
            type="number"
            id="userId"
            value={userIdInput}
            onChange={handleUserChange}
            min="1"
          />
          {currentUser ? (
            <span className="user-name-display">Logged in: {currentUser.name}</span>
          ) : (
            <span style={{ color: '#e74c3c', fontSize: '12px' }}>User #{currentUserId} (Not Found)</span>
          )}
        </div>
      </nav>

      <Routes>
        <Route path="/" element={<BookList currentUserId={currentUserId} />} />
        <Route path="/borrows" element={<MyBorrows currentUserId={currentUserId} />} />
        <Route path="/notifications" element={<Notifications currentUserId={currentUserId} />} />
        <Route path="/admin" element={<AdminBooks onUserAdded={() => fetchUserDetails(currentUserId)} />} />
      </Routes>
    </div>
  );
}

export default App;
